class Solution:
    def hammingWeight(self, n: int) -> int:
        count = 0
        while n > 0:
            count += n & 1
            n >>= 1
        return count

if __name__ == '__main__':
    s = Solution()
    print(s.hammingWeight(-3))  # Output: 2
    print(s.hammingWeight(5))  # Output: 2

